import React, { useState } from "react";
import "./CalendarPage.scss";
import { Course } from "../../Types/course";
import { Deadline as ImportedDeadline } from "../../Types/deadline";
import { Sidebar } from "../../сomponents/Sidebar";

// Интерфейсы оставляем без изменений
interface Deadline {
  id: string;
  courseId: string;
  taskName: string;
  dueDate: Date;
  status: "upcoming" | "completed";
}

interface CalendarPageProps {
  currentPage: string;
  deadlines: ImportedDeadline[];
  courses: Course[];
  onNavigate: (page: string) => void;
  onLogout: () => void;
  onAddDeadline: (deadline: Omit<Deadline, "id">) => void;
}

const TopBar: React.FC<{ userName: string }> = ({ userName }) => (
  <header className="calendar-topbar">
    <div className="calendar-topbar__content">
      <h1 className="calendar-topbar__title">Academic Calendar</h1>
      <div className="calendar-topbar__user">
        <span className="calendar-topbar__user-name">Welcome {userName || 'Student'}!</span>
      </div>
    </div>
  </header>
);

const DeadlineModal: React.FC<{
  courses: Course[];
  onSave: (deadline: Omit<Deadline, "id">) => void;
  onClose: () => void;
}> = ({ courses, onSave, onClose }) => {
  const [taskName, setTaskName] = useState("");
  const [selectedCourseId, setSelectedCourseId] = useState("");
  const [dueDate, setDueDate] = useState("");

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!taskName || !selectedCourseId || !dueDate) return;
    onSave({ courseId: selectedCourseId, taskName, dueDate: new Date(dueDate), status: "upcoming" });
    onClose();
  };

  return (
    <div className="calendar-modal-overlay" onClick={onClose}>
      <div className="calendar-modal" onClick={(e) => e.stopPropagation()}>
        <div className="calendar-modal__header">
          <h3 className="calendar-modal__title">Add New Deadline</h3>
          <button onClick={onClose} className="calendar-modal__close-btn">×</button>
        </div>
        <form onSubmit={handleSubmit} className="calendar-modal__form">
          <div className="calendar-form-group">
            <label className="calendar-form-label">Task Name</label>
            <input type="text" value={taskName} onChange={(e) => setTaskName(e.target.value)} className="calendar-form-input" required placeholder="Enter task name" />
          </div>
          <div className="calendar-form-group">
            <label className="calendar-form-label">Course</label>
            <select value={selectedCourseId} onChange={(e) => setSelectedCourseId(e.target.value)} className="calendar-form-select" required>
              <option value="">Select a course</option>
              {courses.map((course) => <option key={course.id} value={course.id}>{course.title}</option>)}
            </select>
          </div>
          <div className="calendar-form-group">
            <label className="calendar-form-label">Due Date</label>
            <input type="date" value={dueDate} onChange={(e) => setDueDate(e.target.value)} className="calendar-form-input" required />
          </div>
          <div className="calendar-modal__actions">
            <button type="button" className="calendar-btn calendar-btn--secondary" onClick={onClose}>Cancel</button>
            <button type="submit" className="calendar-btn calendar-btn--primary">Save Deadline</button>
          </div>
        </form>
      </div>
    </div>
  );
};

export function CalendarPage({ currentPage, deadlines, courses, onNavigate, onLogout, onAddDeadline }: CalendarPageProps) {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [showAddModal, setShowAddModal] = useState(false);

  // Хелперы
  const getCourseById = (id: string) => courses.find((c) => c.id === id);
  const monthNames = ["January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"];
  const totalDays = new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 0).getDate();
  const startDay = new Date(currentDate.getFullYear(), currentDate.getMonth(), 1).getDay();

  const days = [];
  for (let i = 0; i < startDay; i++) days.push(null);
  for (let day = 1; day <= totalDays; day++) days.push(day);

  return (
    <div className="calendar-page">
      <Sidebar currentPage={currentPage} onNavigate={onNavigate} onLogout={onLogout} />
      <div className="calendar-main-content">
        <TopBar userName="" />
        <main className="calendar-content">
          <div className="calendar-container">
            <section className="calendar-widget">
              <div className="calendar-widget__header">
                <h2 className="calendar-widget__title">{monthNames[currentDate.getMonth()]} {currentDate.getFullYear()}</h2>
                <div className="calendar-widget__controls">
                  <div className="calendar-widget__nav-group">
                    <button onClick={() => setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1))} className="calendar-widget__nav-btn">‹</button>
                    <button onClick={() => setCurrentDate(new Date())} className="calendar-btn calendar-btn--today">Today</button>
                    <button onClick={() => setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1))} className="calendar-widget__nav-btn">›</button>
                  </div>
                  <button onClick={() => setShowAddModal(true)} className="calendar-btn calendar-btn--add">+ Add Deadline</button>
                </div>
              </div>

              <div className="calendar-widget__grid">
                {["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"].map(day => (
                  <div key={day} className="calendar-widget__day-header">{day}</div>
                ))}
                {days.map((day, idx) => {
                  if (day === null) return <div key={`empty-${idx}`} className="calendar-widget__day calendar-widget__day--empty" />;

                  const dayDeadlines = deadlines.filter(d => {
                    const dd = new Date(d.dueDate);
                    return dd.getDate() === day && dd.getMonth() === currentDate.getMonth() && dd.getFullYear() === currentDate.getFullYear();
                  });
                  const isToday = new Date().toDateString() === new Date(currentDate.getFullYear(), currentDate.getMonth(), day).toDateString();

                  return (
                    <div key={day} className={`calendar-widget__day ${isToday ? 'calendar-widget__day--today' : ''}`}>
                      <span className={`calendar-widget__day-number ${isToday ? 'calendar-widget__day-number--today' : ''}`}>{day}</span>
                      <div className="calendar-widget__events">
                        {dayDeadlines.slice(0, 2).map(dl => (
                          <div key={dl.id} className="calendar-widget__event-pill" style={{ borderLeftColor: getCourseById(dl.courseId)?.color }}>
                            {dl.taskName}
                          </div>
                        ))}
                        {dayDeadlines.length > 2 && <span className="calendar-widget__more">+{dayDeadlines.length - 2}</span>}
                      </div>
                    </div>
                  );
                })}
              </div>
            </section>

            <aside className="calendar-sidebar-info">
              <div className="calendar-sidebar-card">
                <h3 className="calendar-sidebar-card__title">Upcoming Tasks</h3>
                <div className="calendar-deadlines-list">
                  {/* Твой список дедлайнов будет здесь */}
                  <p className="calendar-sidebar-card__empty">No deadlines this week</p>
                </div>
              </div>
            </aside>
          </div>
        </main>
      </div>
      {showAddModal && <DeadlineModal courses={courses} onSave={onAddDeadline} onClose={() => setShowAddModal(false)} />}
    </div>
  );
}
